import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Safe code that securely handles user input
        int maxLength = 10;
        char[] buffer = new char[maxLength];

        // Truncate the input if it exceeds maxLength
        userInput.getChars(0, Math.min(userInput.length(), maxLength), buffer, 0);

        System.out.println("Hello, " + new String(buffer));
    }
}

